## ProxySQL admin CLI

```bash
# Connect to admin interface
docker exec -it proxysql mysql -u admin -padminpass -h 127.0.0.1 -P 6032

# Flush query cache
PROXYSQL FLUSH QUERY CACHE;

# Change cache TTL live (no restart)
UPDATE mysql_query_rules SET cache_ttl=60000 WHERE rule_id=3;
LOAD MYSQL QUERY RULES TO RUNTIME;

# SHUN a backend (drain, no new connections)
UPDATE mysql_servers SET status='SHUNNED' WHERE hostname='mysql-replica1';
LOAD MYSQL SERVERS TO RUNTIME;

# Bring it back
UPDATE mysql_servers SET status='ONLINE' WHERE hostname='mysql-replica1';
LOAD MYSQL SERVERS TO RUNTIME;
SAVE MYSQL SERVERS TO DISK;

# Watch live query digest (reset counters first)
SELECT * FROM stats_mysql_query_digest_reset;   -- resets counters, returns snapshot
```
